# Simplified CDN edge server config
proxy_cache_path /var/cache/cdn levels=1:2
    keys_zone=images:100m
    max_size=50g
    inactive=24h
    use_temp_path=off;

server {
    listen 443 ssl http2;
    server_name cdn.example.com;

    location /images/ {
        proxy_cache images;
        proxy_cache_valid 200 1h;
        proxy_cache_valid 404 1m;

        # Serve stale content while revalidating in background
        proxy_cache_use_stale updating error timeout;
        proxy_cache_background_update on;

        # Add cache status header for debugging
        add_header X-Cache-Status $upstream_cache_status;
        add_header Cache-Control "public, max-age=3600";

        # Conditional requests to origin
        proxy_cache_revalidate on;

        proxy_pass http://origin-servers;
    }
}
